INSERT INTO public.photos VALUES (22018, 'Arenas S.D. 1946', 'Vista parcial del terreno donde el club Arenas S.D. de "football" jugaba como local, junto al que fuera antiguo barrio "de la Paciencia", entre el camino de San Josâ”œآ® (izquierda) y el de Cabaldâ”œâ”‚s, y las calles Carbâ”œâ”‚ y Castelar, muy cerca del Frontâ”œâ”‚n Zaragozano. En 1967, este campo cesâ”œâ”‚ en sus funciones deportivas, y fue urbanizado inmediatamente, como parte de la zona baja del barrio de San Josâ”œآ®. En la imagen, y tras las parcelas del fondo, la larga calle de la Uniâ”œâ”‚n (antigua de Carbâ”œâ”‚), y las pequeâ”œâ–’as calles de General Ricardos, y del Salvador. Por entre los tejados de literal teja, sobresale el remate de la torre del asilo de ancianos de las "Hermanitas de los Pobres", diseâ”œâ–’ado por Ricardo Magdalena.', 1946, 1946, 1946, 'Anos 40', 'SAN JOSâ”œأ«', 41.64126500, -0.87080500, '0101000020E61000005A2F8672A2DDEBBFE388B5F814D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49421720657.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49421720657.webp', 'https://www.flickr.com/photos/zaragozaantigua/49421720657/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22106, 'Camino Puente Virrey aâ”œâ–’os 50', 'Imagen familiar tomada en el camino del Puente del Virrey del barrio de San Josâ”œآ® de Zaragoza, a la altura de la actual plaza Mayor. A la derecha se abrirâ”œأ­ la calle Raquel Meyer. Fuente: www.facebook.com/photo.php?fbid=10204194390557272&set...', 1950, 1950, 1959, 'Anos 50', 'SAN JOSâ”œأ«', 41.63790400, -0.87430400, '0101000020E61000002C62D8614CFAEBBF69FE98D6A6D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21094420910.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21094420910.webp', 'https://www.flickr.com/photos/zaragozaantigua/21094420910/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22203, 'Iglesia de San Josâ”œآ® 1953', 'Dibujo de la fachada y planta de la que fue proyectada por Regino y Josâ”œآ® Borobio como iglesia de la barriada de San Josâ”œآ®, en una estratâ”œآ®gica ubicaciâ”œâ”‚n chaflanera entre la calle de Cartagena (a la izquierda), el camino del Puente del Virrey y la avenida de San Josâ”œآ®. Vinculada al Patronato del canâ”œâ”‚nigo Agustâ”œآ،n Gericâ”œâ”‚, junto a las escuelas por â”œآ®l fundadas, aparecâ”œآ،a vertebrada en tres naves y presentaba una llamativa torre-campanario exenta de cuarenta metros de altura. No fue realizada. Fuente visual: AMZ.', 1953, 1953, 1953, 'Anos 50', 'SAN JOSâ”œأ«', 41.63991000, -0.87359500, '0101000020E6100000315F5E807DF4EBBF12312592E8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37894644092.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37894644092.webp', 'https://www.flickr.com/photos/zaragozaantigua/37894644092/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22517, 'Calle de Santa Rosa c.1964', 'Luminosa y familiar estampa capturada junto al inmueble del nâ”¬â•‘ 16 de la calle de Santa Rosa, esquinero con el cruce de la reciente calle de Luis Braille, que por detrâ”œأ­s la cruza en un espacio recientemente urbanizado donde antes estuviera el campo de deportes de San Josâ”œآ® del Arenas. Hacia el fondo y a la derecha, modernos bloques de los nâ”œâ•‘meros 9 y 11 de este reciente tramo de Santa Rosa, y el angular nâ”¬â•‘ 1 de Luis Braille. En esa misma acera y a continuaciâ”œâ”‚n destaca la antigua parcela del nâ”¬â•‘ 3 de Santa Rosa, seguida por el moderno edificio de viviendas del nâ”¬â•‘ 30 de la calle del Privilegio de la Uniâ”œâ”‚n, que al fondo muestra la antigua parcela del nâ”¬â•‘ 31 de la que fuera calle de Carbâ”œâ”‚ del barrio de la Paciencia, que luego serâ”œآ،a derribada y sobre cuyo solar se construyâ”œâ”‚ a principios de los aâ”œâ–’os ochenta el actual inmueble del nâ”¬â•‘ 29 y 31 de Privilegio de la Uniâ”œâ”‚n.', 1964, 1964, 1964, 'Anos 60', 'SAN JOSâ”œأ«', 41.64089600, -0.87139600, '0101000020E6100000D9AF3BDD79E2EBBF901150E108D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52350301955.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52350301955.webp', 'https://www.flickr.com/photos/zaragozaantigua/52350301955/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22634, 'La Granja 1975', 'Los campos de cultivo de la antigua Granja Experimental de Zaragoza se extendâ”œآ،an a ambos lados de la vâ”œآ،a de los ferrocarriles a Barcelona. Para salvar la trinchera del tren, que por aquâ”œآ، seguâ”œآ،a al aire una vez cubierto el tramo Goya-Tenor Fleta-cruce con el Camino del Puente del Virrey, existâ”œآ،a tiempo ha este puentecito peatonal unos 60 m. despuâ”œآ®s del Grupo de Viviendas Puente Virrey-Rosellâ”œâ”‚n (lado derecho de las vâ”œآ،as), y a unos 40 m. de las parcelas de Emilio Mario, Alegrâ”œآ،a y Nobleza (lado izquierdo de las vâ”œآ،as). En 1943 la Granja fue abandonada, y se construyeron los edificios de viviendas del triangular bloque de la nueva calle Josâ”œآ® Galiay. Pasaron las dâ”œآ®cadas, y el entorno apenas se modificâ”œâ”‚. Las acequias seguâ”œآ،an al aire, los campos se cultivaban, las ovejas y cabras ramoneaban, y la chavalerâ”œآ،a y tercera edad hacâ”œآ،an de estos lares su lugar de juego, convivencia y sociabilidad. En la imagen, un rebaâ”œâ–’o de ovejas rasas y cabras cruza el puente peatonal (porque peatones lo somos todos los animales), en direcciâ”œâ”‚n a los abrevaderos del Camino de Cabaldâ”œâ”‚s. Al fondo, a la izquierda, se perfila la silueta del silo de cereales del Ministerio de Agricultura sito en la carretera de Castellâ”œâ”‚n, y las industriosas chimeneas de la abandonada fâ”œأ­brica de cementos Portland nos conducen al blanco edificio de viviendas de la estaciâ”œâ”‚n de Miraflores. Inmediato, sobre las vâ”œآ،as, el Camino de Cabaldâ”œâ”‚s convertido en paso para vehâ”œآ،culos a motor de explosiâ”œâ”‚n. En la actualidad, en este mismo punto termina la breve prolongaciâ”œâ”‚n de Tenor Fleta. Una metâ”œأ­lica valla da perspectiva del sarcâ”œâ”‚fago de cemento que alcanza hasta el Tercer Cinturâ”œâ”‚n, donde deberâ”œآ،a de haber llegado hace tiempo, mientras los vehâ”œآ،culos han de dar la vuelta para volver hacia donde han venido. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63554000, -0.87270400, '0101000020E61000000BD462F030EDEBBF61A6ED5F59D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20236297745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20236297745.webp', 'https://www.flickr.com/photos/zaragozaantigua/20236297745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24946, 'Vista de Zaragoza 1924', 'Hay fotografâ”œآ،as que suplen la nitidez con la sugerencia, y esta del archivo Francisco Gâ”œâ”‚rriz, es una de ellas. Capturada desde las alturas del Cabezo de Buenavista, que por la derecha desciende desde el paseo del Canal hacia el cauce del râ”œآ،o Huerva. Mâ”œأ­s allâ”œأ­, huertas y campos de cultivo de la ribera de este râ”œآ،o, en el entorno del camino del Sâ”œأ­bado, el viejo camino de Cuarte, y el paseo de los Ruiseâ”œâ–’ores. A la derecha, algunos de los edificios del paseo de los Ruiseâ”œâ–’ores, como el reciente colegio Pompiliano de las MM. Escolapias, tan destacado por la notable diferencia de cota de altura de unas terrazas naturales, y otras. El ciudadano que acaba de salir del camino viejo de Cuarte nos seâ”œâ–’ala el curso, a la inversa, de la acequia de las Adulas o de San Josâ”œآ®, que por ahâ”œآ، continâ”œâ•‘a su largo recorrido al aire hasta el camino de las Torres y mucho mâ”œأ­s allâ”œأ­. En descenso desde el Canal Imperial, el cauce de la derivaciâ”œâ”‚n de agua que abastecâ”œآ،a a la fâ”œأ­brica de harinas de Monares y que unos metros mâ”œأ­s abajo desembocaba en la acequia de las Adulas. Al fondo, como un escâ”œآ®nico telâ”œâ”‚n, la ciudad y sus emergentes torres y câ”œâ•‘pulas, cuando seguâ”œآ،an siendo los referentes edilicios visualmente mâ”œأ­s destacados.', 1924, 1924, 1924, 'Anos 20', 'UNIVERSIDAD', 41.63421300, -0.89280800, '0101000020E6100000EC6D3315E291ECBF5AD93EE42DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28009925163.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28009925163.webp', 'https://www.flickr.com/photos/zaragozaantigua/28009925163/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22635, 'La Granja 1975', 'Captura parcial de algunos de los edificios que formaban parte del enorme complejo de la antigua Granja Agrâ”œآ،cola Experimental, creada en 1881 y abandonada desde 1943. Hasta su derribo para construir el nuevo Colegio Pâ”œâ•‘blico Calixto Ariâ”œâ–’o-Hilario Val, fue una de las emblemâ”œأ­ticas "solanas" del barrio donde las yayas y yayos, venidos con las ornadas de expulsados de los pueblos, se iban a echar la maâ”œâ–’ana y la tarde. El alto edificio de la izquierda habâ”œآ،a sido el pabellâ”œâ”‚n docente de la instituciâ”œâ”‚n, diseâ”œâ–’ado por el arquitecto municipal Fâ”œآ®lix Navarro. Los bancos adosados fueron aâ”œâ–’adido posterior, en las esquinas mâ”œأ­s guarnecidas. Lo mismo sucedâ”œآ،a con el edificio del centro, que fue antiguo cocherâ”œâ”‚n para la maquinaria agrâ”œآ،cola utilizada en las clases prâ”œأ­cticas. El edificio de la derecha se construyâ”œâ”‚ sobre la original bâ”œأ­scula para carros tirados por mulos. Los campos de los alrededores siguieron siendo cultivados de herbâ”œأ­ceos y maâ”œآ،z unos aâ”œâ–’os mâ”œأ­s, hasta 1978-79. Al fondo de la imagen, uno de los arcos de la antigua fâ”œأ­brica de briquetas asociada a la Estaciâ”œâ”‚n de ferrocarril de Zaragoza a Utrillas, en la actual calle Ducado de Atenas, donde hoy se levanta el pabellâ”œâ”‚n municipal de deportes P. Felipe. Mâ”œأ­s al fondo, algunos de los industriosos edificios de Miguel Servet. Fuente visual: AVV San Josâ”œآ®', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20242766662.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20242766662.webp', 'https://www.flickr.com/photos/zaragozaantigua/20242766662/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22638, 'La Granja 1975', 'Imagen del edificio a doble vertiente del antiguo "cocherâ”œâ”‚n de maquinaria agrâ”œآ،cola" de la Granja Agrâ”œآ،cola Experimental de Zaragoza, ya convertido hacâ”œآ،a tiempo en comunitario y oficioso espacio al aire libre de reuniâ”œâ”‚n social del barrio, como solanera en invierno, y fresquera en verano. Tras â”œآ®l, campos de cultivo de maâ”œآ،z en lo que fueran antiguos jardines del acceso principal a los pabellones de la Granja. A la izquierda, el antiguo y gran edificio con funciones de residencia de estudiantes "granjeros", mostrando inequâ”œآ،vocas seâ”œâ–’ales del mal paso de los aâ”œâ–’os, tras el abandono de estas instalaciones, varias dâ”œآ®cadas antes. Al fondo, entre los dos edificios de la Granja, despunta la rotunda torre de la fâ”œأ­brica GIESA-Schindler, al otro lado de la calle Miguel Servet. A la izquierda, bloques cercanos al camino del Junco. Pocos aâ”œâ–’os despuâ”œآ®s, esta zona representada serâ”œآ،a profundamente modificada. Fuente visual: AVV. San Josâ”œآ®', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20353031476.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20353031476.webp', 'https://www.flickr.com/photos/zaragozaantigua/20353031476/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22640, 'Tren Miraflores 1975', 'Imagen de un convoy transitando bajo el puente peatonal sobre las vâ”œآ،as del ferrocarril Madrid-Barcelona. A la izquierda, al fondo, chimeneas de la fâ”œأ­brica de Cementos de Miraflores. A la derecha, el aterrazado descenso desde el Camino de Miraflores, con parcial vista de las "Casas de los Americanos". Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63554000, -0.87270400, '0101000020E61000000BD462F030EDEBBF61A6ED5F59D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20412743472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20412743472.webp', 'https://www.flickr.com/photos/zaragozaantigua/20412743472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22896, 'Parque La Granja 1989', 'Vista aâ”œآ®rea sobre el barrio de San Josâ”œآ® centrada en la construcciâ”œâ”‚n del Parque de La Granja, que muestra el trazado de sus viales internos y los espacios donde luego se instalarâ”œأ­n diversos complementos. Este nuevo parque suponâ”œآ،a la ampliaciâ”œâ”‚n de la arbolada zona que, a su izquierda, se habâ”œآ،a trazado unos aâ”œâ–’os antes entre la calle de Josâ”œآ® Galiay y el camino de Cabaldâ”œâ”‚s, y que junto al Colegio Pâ”œâ•‘blico Calixto Ariâ”œâ–’o-Hilario Val, el Colegio Pâ”œâ•‘blico de Educaciâ”œâ”‚n Especial â”œأ¼ngel Riviâ”œآ؟re, y el nuevo parque, ocupaban el espacio donde estuviera la antigua Granja Agrâ”œآ،cola de Zaragoza. Vertebrann la escena las vâ”œآ،as del ferrocarril, ya soterradas hasta el puentecillo peatonal de la calle de Luis Aula. Tras el parque, el Centro Deportivo Municipal La Granja, y a la derecha la estaciâ”œâ”‚n de Miraflores. Al fondo, obras del nuevo pabellâ”œâ”‚n municipal de deportes, y la Facultad de Veterinaria.', 1989, 1989, 1989, 'Anos 80', 'SAN JOSâ”œأ«', 41.63518400, -0.87141900, '0101000020E6100000E59D4319AAE2EBBFA37895B54DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20552947004.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20552947004.webp', 'https://www.flickr.com/photos/zaragozaantigua/20552947004/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22283, 'Calle de Rodrigo Rebolledo 1962', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Noviembre 1962. "Calles de Zaragoza." Imagen de la calle Rodrigo Rebolledo (este tramo, desde 1974, serâ”œأ­ denominado Monasterio Nâ”¬آ¬ Sâ”¬آ¬ de El Pueyo), con visual, al fondo, de Compromiso de Caspe. A la izquierda, las vâ”œآ،as de la lâ”œآ،nea 17 del tranvâ”œآ،a ("Las Fuentes"), inaugurada en 1957 para unir la Plaza de Espaâ”œâ–’a con Salvador Minguijâ”œâ”‚n, aunque ya en 1961 el trayecto serâ”œأ­ recortado a Rodrigo Rebolledo. Al fondo, el Grupo de Viviendas "Casta â”œأ¼lvarez", y la esquina del Matadero en que nacen Florentino Ballesteros y Monasterio de Samos.', 1962, 1962, 1962, 'Anos 60', 'LAS FUENTES', 41.64613100, -0.86768300, '0101000020E6100000047289230FC4EBBF44F7AC6BB4D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15049357997.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15049357997.webp', 'https://www.flickr.com/photos/zaragozaantigua/15049357997/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23040, 'Calle de Cartagena 1994', 'Imagen capturada durante la urbanizaciâ”œâ”‚n de la calle de Cartagena al objeto de prepararla para conectar la avenida de Cesâ”œأ­reo Alierta, al fondo, con la prolongaciâ”œâ”‚n de la misma que ya estaba construida desde esta calle y hasta el Pabellâ”œâ”‚n Municipal de Deportes Prâ”œآ،ncipe Felipe. La intervenciâ”œâ”‚n incluâ”œآ،a la renovaciâ”œâ”‚n de las redes de abastecimiento de agua, alcantarillado, alumbrado pâ”œâ•‘blico, semaforizaciâ”œâ”‚n, etcâ”œآ®tera, ademâ”œأ­s de la pavimentaciâ”œâ”‚n de las aceras, calzada y medianas, de forma similar que el tramo ya realizado. Con esta urbanizaciâ”œâ”‚n, a la prolongaciâ”œâ”‚n de la avenida de Cesâ”œأ­reo Alierta ya sâ”œâ”‚lo le quedaba pendiente de realizaciâ”œâ”‚n el tramo comprendido entre el pabellâ”œâ”‚n municipal y el enlace con la carretera de Castellâ”œâ”‚n, cumpliendo asâ”œآ، el proyecto ideado varias dâ”œآ®cadas antes, como forma de conectar de forma directa la circulaciâ”œâ”‚n rodada del centro de la ciudad con la carretera de Castellâ”œâ”‚n, sin tener que pasar por la congestionada calle de Miguel Servet. Con esta obra, la veterana calle de Cartagena desaparecerâ”œآ،a del nomenclâ”œأ­tor urbano.', 1994, 1994, 1994, 'Anos 90', 'SAN JOSâ”œأ«', 41.63921200, -0.87131000, '0101000020E610000036B05582C5E1EBBFFA9AE5B2D1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50380070208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50380070208.webp', 'https://www.flickr.com/photos/zaragozaantigua/50380070208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23203, 'Calle San Luis de Francia 2010', 'Aspecto de la calle de San Luis de Francia, con la del Privilegio de la Uniâ”œâ”‚n al fondo, en enero de 2010. El solar de la izquierda, perteneciente al nâ”œâ•‘mero 21, fue acondicionado como espacio de ocio en 2015. Este entorno se da en denominar Isla de San Josâ”œآ®, y es uno de los mâ”œأ­s envejecidos de la ciudad. Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.64172600, -0.87082900, '0101000020E61000007B116DC7D4DDEBBF177FDB1324D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32548808403.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32548808403.webp', 'https://www.flickr.com/photos/zaragozaantigua/32548808403/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23210, 'Calle Santa Rosa 2010', 'Foto: Oliver Duch. Vista de la calle de Santa Rosa, tramo comprendido entre las de Antonio Maura y Emilio Castelar (al fondo). El solar de la derecha serâ”œأ­ objeto de acondicionamiento en 2011 dentro del programa municipal "Esto no es un solar". Fuente: Heraldo de Aragâ”œâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.64078800, -0.87231000, '0101000020E61000000B293FA9F6E9EBBFAAD5575705D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33383878816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33383878816.webp', 'https://www.flickr.com/photos/zaragozaantigua/33383878816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23228, 'C.â”¬â•‘ del Puente del Virrey 2014', 'Imagen del portâ”œâ”‚n de ingreso a la antigua Quinta de San Josâ”œآ®, que destaca por el remate en forja a modo de dintel o tâ”œآ،mpano donde pueden leerse las letras en chapa soldada con la leyenda "Quinta/San Josâ”œآ®". Junto a â”œآ®l y hacia la derecha, restos de la antigua Torre de la viuda de Mariano Lâ”œâ”‚pez, esquinera con la calle de Pablo Remacha y la plaza Mayor de San Josâ”œآ®. Este portâ”œâ”‚n permitâ”œآ،a el ingreso desde el camino del Puente del Virrey a un camino que varias decenas de metros hacia el fondo, conducâ”œآ،a hasta la referida Quinta. Unos meses despuâ”œآ®s de capturada la presente imagen, estos restos edilicios de finales del siglo XIX-principios del siglo XX fueron derribados durante el proceso de ampliaciâ”œâ”‚n del colegio concertado (privado sostenido con fondos pâ”œâ•‘blicos) Agustâ”œآ،n Gericâ”œâ”‚, perdurando sâ”œâ”‚lo la referida reja del portâ”œâ”‚n que aâ”œâ–’os despuâ”œآ®s fue restaurada y reinstalada en una râ”œآ®plica en hormigâ”œâ”‚n del portâ”œâ”‚n diseâ”œâ–’ada por el arquitecto Ricardo Usâ”œâ”‚n Garcâ”œآ،a, que fue ubicada en 2022 como puerta monumental en un cercano parterre ajardinado del andador central de la avenida de Cesâ”œأ­reo Alierta (a la izquierda de la fotografâ”œآ،a, fuera de plano).', 2014, 2014, 2014, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63927800, -0.87377000, '0101000020E6100000BD3AC780ECF5EBBFB1868BDCD3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54396033740.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54396033740.webp', 'https://www.flickr.com/photos/zaragozaantigua/54396033740/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24381, 'Quinta Julieta c.1958', '"Casa de Ejercicios espirituales "Quinta Julieta", en el Paseo del Canal. Fachada principal. Aparcado, un Seat 600". La denominada "casa de ejercicios de la Compaâ”œâ–’â”œآ،a de Jesâ”œâ•‘s en la Quinta Julieta", propiedad de los PP. Jesuitas, fue construida segâ”œâ•‘n proyecto del arquitecto Santiago Lagunas en el aâ”œâ–’o 1958, en terrenos de la antigua "Quinta de Julieta Sagols", junto al Canal Imperial, al sur del Cabezo Cortado. De ella conservâ”œâ”‚ el nombre, y algunos restos de las maravillas que formaron parte de este espacio con acceso pâ”œâ•‘blico, antes de su conversiâ”œâ”‚n en un lugar exclusivo y confesional. El frontal curvo de la imagen es el nexo de uniâ”œâ”‚n entre los dos pabellones laterales, y el resto de dependencias traseras. El ingreso desde el paseo del Canal se realiza por la izquierda, en pronunciado desnivel. Al fondo, tras el edificio, la estaciâ”œâ”‚n del ferrocarril de Utrillas. A la derecha, tras otro importante descenso, el antiguo camino de Miraflores y la acequia del Ontonar. Fuente visual: Archivo Coyne (DARA-AHPZ).', 1958, 1958, 1958, 'Anos 50', 'SAN JOSâ”œأ«', 41.62540500, -0.86995700, '0101000020E610000005A4FD0FB0D6EBBFA0E062450DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22252128833.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22252128833.webp', 'https://www.flickr.com/photos/zaragozaantigua/22252128833/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24395, 'Luis Aula 1972', 'Imagen capturada durante las obras de construcciâ”œâ”‚n del nuevo colegio de La Salle "Montemolâ”œآ،n" en la periferia pura y dura del barrio de San Josâ”œآ®, entre las calles Luis Aula (desde donde se ha tomado la imagen), Gascâ”œâ”‚n y Guimbao (derecha), y Josâ”œآ® Galiay (al fondo, a la derecha), donde tenâ”œآ،a radicada su direcciâ”œâ”‚n postal y entrada "magna" (VIP, poco operativa, y escalonada). El curso 1972-1973 fue el que inaugurâ”œâ”‚ estas novâ”œآ،simas instalaciones, frente a la antigua Granja Agrâ”œآ،cola, que todavâ”œآ،a definâ”œآ،a el entorno de la zona con su magna presencia residual, calles de tierra, riegos al aire, moreras, campos de maâ”œآ،z y herbâ”œأ­ceas, y noches oscuras como la boca de un lobo. Este colegio fue construido, precisamente, en uno de esos campos de herbâ”œأ­ceas. En la imagen, los dos grandes pabellones del aulario, rodeados de patios. A la izquierda, sobresale la residencia de los Hermanos de las Escuelas Cristianas. Detrâ”œأ­s, donde despunta la "pluma" de obra, la capilla, las dependencias administrativas, y en otro pabellâ”œâ”‚n aparte, el salâ”œâ”‚n recreativo y el cine. Fuente visual: "Memoria Escolar 1971-1972", amable aportaciâ”œâ”‚n de Juan Carlos Crespo.', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”œأ«', 41.63712100, -0.87126600, '0101000020E61000004DBC033C69E1EBBF234C512E8DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26122422956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26122422956.webp', 'https://www.flickr.com/photos/zaragozaantigua/26122422956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24511, 'La Granja 1908', 'Imagen del inglâ”œآ®s tren de trilla "Ruston", laborando en la Escuela de Agricultura de Zaragoza, en la Granja Agrâ”œآ،cola, como imagen promocional de la casa Alberto Alhes y Câ”¬آ¬., importadora de maquinaria agrâ”œآ،cola. Fuente visual: fotografâ”œآ،a Granja Agrâ”œآ،cola, en "Zaragoza artâ”œآ،stica â”œآ® industrial. Album de la Exposiciâ”œâ”‚n. 1908."', 1908, 1908, 1908, 'Anos 1900', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33757697474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33757697474.webp', 'https://www.flickr.com/photos/zaragozaantigua/33757697474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24540, 'Calle de Juana de Ibarbourou 1973', 'Inâ”œآ®dita imagen capturada con motivo de la inauguraciâ”œâ”‚n del Supermercado Sabeco radicado en los grandes bajos comerciales del modernâ”œآ،simo edificio del nâ”¬â•‘ 5 de la calle de Juana de Ibarbourou, esquinero con la calle del Monasterio de Poblet. Este era el octavo "super" que esta cadena abrâ”œآ،a en Zaragoza, desde que en 1960 inauguraran el pionero Sabeco-Supermax en la calle de las Delicias. Con este reciâ”œآ®n inaugurado se trataba de dar servicio a la entonces denominada "zona de Miguel Servet" y cubrir el â”œأ­rea entre los establecimientos ya abiertos en Las Fuentes (calle de Salvador Minguijâ”œâ”‚n) y en San Josâ”œآ® (avenida de San Josâ”œآ®). A mediados de los aâ”œâ–’os 70 Sabeco era una de las principales empresas del sector servicios en Zaragoza, con algo mâ”œأ­s de 200 empleados, y una importante implantaciâ”œâ”‚n, incluyendo los barrios mâ”œأ­s populosos de la periferia. En la imagen, nutrida fila de expectantes clientas (hacer la compra era cosa de mujeres) de este nuevo "super" esperan su turno para entrar, bajo una festiva decoraciâ”œâ”‚n de globos. Fue tal la aglomeraciâ”œâ”‚n, que tuvieron que abrir las puertas media hora antes de lo previsto. Todo un â”œآ®xito, con notable impacto en el pequeâ”œâ–’o comercio de proximidad.', 1973, 1973, 1973, 'Anos 70', 'SAN JOSâ”œأ«', 41.64245100, -0.86952900, '0101000020E6100000008E3D7B2ED3EBBF292499D53BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51591320388.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51591320388.webp', 'https://www.flickr.com/photos/zaragozaantigua/51591320388/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24947, 'Cabezo Buenavista 1924', 'Imagen del cabezo de Buenavista, sito en el parque del mismo nombre, decorado con el monumento a Alfonso I, obra del escultor Josâ”œآ® Bueno. Aunque el motivo de su erecciâ”œâ”‚n fue el aniversario de la conquista de la ciudad, su instalaciâ”œâ”‚n se consumâ”œâ”‚ unos aâ”œâ–’os despuâ”œآ®s, y sigue pendiente de inaugurarse, parece ser. El felino africano que le caracteriza, a sus pies, llegarâ”œآ،a unos aâ”œâ–’os mâ”œأ­s tarde. Como la imagen ilustra, ya entonces era utilizado como fondo escâ”œآ®nico a fotografâ”œآ،as y recuerdos grâ”œأ­ficos varios. Fuente visual: Francisco Gâ”œâ”‚rriz, Archivo Municipal de Zaragoza', 1924, 1924, 1924, 'Anos 20', 'UNIVERSIDAD', 41.63366800, -0.89333800, '0101000020E610000000C5C8923996ECBFC84274081CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29812049400.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29812049400.webp', 'https://www.flickr.com/photos/zaragozaantigua/29812049400/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24567, 'La Granja 1915', 'Imagen de la oficial inauguraciâ”œâ”‚n, en la Granja agrâ”œآ،cola experimental, de un busto en homenaje a Manuel Rodrâ”œآ،guez Ayuso, prâ”œâ”‚cer local que fuera director de esta instituciâ”œâ”‚n desde 1891 a 1908. Este busto fue una de las primeras obras del escultor Josâ”œآ® Julio Bueno, luego mâ”œأ­s reconocido por el monumento de la Fosa Comâ”œâ•‘n de Torrero (1919), el Batallador del Cabezo de Buenavista (1921), la "Mujer dormida" de la plaza de Basilio Paraâ”œآ،so (1921), et caetera. En la imagen, el busto se localiza en el acceso principal, desde el camino del Bajo Aragâ”œâ”‚n, muy al fondo, a las instalaciones centrales de la Granja. A la izquierda, el campo de experimentaciâ”œâ”‚n de cereales. A la derecha, la pequeâ”œâ–’a garita meteorolâ”œâ”‚gica. Al fondo, los dos edificios que flanqueaban la entrada junto al camino de Cabaldâ”œâ”‚s. Cuando la Granja fue clausurada en 1943, la estatua estuvo desaparecida casi cuarenta aâ”œâ–’os (signo de los tiempos), hasta que el CITA (Centro de Investigaciâ”œâ”‚n y Tecnologâ”œآ،a Agroalimentaria de Aragâ”œâ”‚n) la hizo aparecer para reinstalarla (demediada) en la entrada de sus modernas instalaciones del campus de Montaâ”œâ–’ana. En la actualidad, el espacio de la foto forma parte de los amplios patios de juego y recreo del colegio pâ”œâ•‘blico bilingâ”œâ•‌e "Calixto Ariâ”œâ–’o-Hilario Val". Fuente visual: Foto Serrano Sancho ("Mundo Grâ”œأ­fico").', 1915, 1915, 1915, 'Anos 10', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20040957118.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20040957118.webp', 'https://www.flickr.com/photos/zaragozaantigua/20040957118/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24572, 'La Granja 1930', 'Captura de los edificios principales de la Granja Agrâ”œآ،cola Experimental de Zaragoza. El edificio central era el de la Direcciâ”œâ”‚n de la Granja. En 1930 el ingeniero agrâ”œâ”‚nomo Josâ”œآ® Cruz Lapazarâ”œأ­n ejercâ”œآ،a esas funciones. En los ornamentales jardines del acceso al edificio estaba el Monumento al fundador de La Granja, Manuel Rodrâ”œآ،guez Ayuso, y muy cerca, la garita meteorolâ”œâ”‚gica. A sus flancos, los pabellones residencial y de vivienda del alumnado, y el de laboratorios y pruebas prâ”œأ­cticas. En los sâ”œâ”‚tanos habâ”œآ،a espacio para pruebas con hongos y setas, asâ”œآ، como para una interesante bodega de caldos. A la derecha, los establos, caseta de peones, y apriscos. A la izquierda, fuera de plano, el lavadero de coches, la bâ”œأ­scula para carros, el cocherâ”œâ”‚n de maquinaria agrâ”œآ،cola, el semillero, el gallinero, y las cochiqueras. Los campos de experimentaciâ”œâ”‚n de esta zona "noble" eran un compendio de todos los "palos" que La Granja tocaba: cereales, vides, hortofrutâ”œآ،colas, herbâ”œأ­ceos, maâ”œآ،z, remolacha, plantas medicinales... El acceso a La Granja se hacâ”œآ،a desde Miguel Servet, por un camino que cruzaba los enormes campos de experimentaciâ”œâ”‚n, la lâ”œآ،nea minera Zaragoza-Utrillas, y el Camino de Cabaldâ”œâ”‚s. Al fondo, y tras los edificios de los pabellones, transitaba la lâ”œآ،nea de ferrocarril de los directos a Barcelona. En la actualidad, aquâ”œآ، se encuentran el Parque de La Granja, el CEIP bilingâ”œâ•‌e (alemâ”œأ­n-espaâ”œâ–’ol) Calixto Ariâ”œâ–’o-Hilario Val, y el CPEE â”œأ¼ngel Riviâ”œآ؟re. Fuente visual: "Granja Agrâ”œآ،cola de Zaragoza. Su cincuentenario. Homenaje y gratitud."', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20259226271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20259226271.webp', 'https://www.flickr.com/photos/zaragozaantigua/20259226271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24573, 'La Granja 1883', '"Establecimientos de enseâ”œâ–’anza agrâ”œآ،cola. Zaragoza. Proyecto de una Granja-Escuela, actualmente en construcciâ”œâ”‚n, segâ”œâ•‘n planos del arquitecto D. Fâ”œآ®lix Navarro". Fuente visual: "La Ilustraciâ”œâ”‚n espaâ”œâ–’ola y americana", 1883.', 1883, 1883, 1883, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20337026809.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20337026809.webp', 'https://www.flickr.com/photos/zaragozaantigua/20337026809/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24576, 'La Granja 1930', 'Posado de un grupo de chavales becados por el ministerio de Trabajo, que con edades comprendidas entre los 14 y los 18 aâ”œâ–’os, realizaban un cursillo de capacitaciâ”œâ”‚n de tres meses de duraciâ”œâ”‚n en las instalaciones de la Granja Agrâ”œآ،cola de Zaragoza. Junto a ellos, el director de la Granja, Josâ”œآ® Cruz Lapazarâ”œأ­n, y los profesores Mariano Gros, Antonio Vela, Francisco Guerra, y Lucio Serrano. Detrâ”œأ­s del grupo, el monumento a Manuel Rodrâ”œآ،guez Ayuso, y vista parcial de algunos pabellones granjeros. Fuente visual: Miguel Marâ”œآ،n Chivite, periâ”œâ”‚dico "Heraldo de Aragâ”œâ”‚n".', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32447165261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32447165261.webp', 'https://www.flickr.com/photos/zaragozaantigua/32447165261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24579, 'La Granja 1930', 'Operarios de la Granja Agrâ”œآ،cola en tareas de recolecciâ”œâ”‚n de alfalfa y experimentaciâ”œâ”‚n con abonos "catalâ”œآ،ticos" para buscar la fijaciâ”œâ”‚n del nitrâ”œâ”‚geno atmosfâ”œآ®rico, acelerando asâ”œآ، la mineralizaciâ”œâ”‚n y activaciâ”œâ”‚n de la vida microbiana en suelos carentes o pobres de nutrientes. La imagen estâ”œأ­ capturada en el campo de experimentaciâ”œâ”‚n inmediato al pabellâ”œâ”‚n docente de la escuela de Peritos (al fondo, a la derecha). Junto a este pabellâ”œâ”‚n estaba la bâ”œأ­scula para carros y el lavadero de coches. Los â”œأ­rboles jalonan el camino que conducâ”œآ،a a un puentecillo peatonal de paso sobre las vâ”œآ،as del ferrocarril a Barcelona, a la calle de la Granja Modelo, y al camino del Puente del Virrey. Fuente visual: "Homenaje y testimonio de gratitud que dedican a la Granja Agrâ”œآ،cola de Zaragoza en el Cincuentenario de su fundaciâ”œâ”‚n, los representantes de la Agricultura e Industrias, agradecidas a su benâ”œآ®fico influjo en el resurgimiento de la economâ”œآ،a general aragonesa".', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63518900, -0.86990300, '0101000020E61000003927F6D03ED6EBBFB4E386DF4DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33872908073.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33872908073.webp', 'https://www.flickr.com/photos/zaragozaantigua/33872908073/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24580, 'La Granja 1930', 'Imagen de un rebaâ”œâ–’o ovino lanar practicando el ramoneo tras la recolecciâ”œâ”‚n del maâ”œآ،z en un campo de la Granja Agrâ”œآ،cola de Zaragoza, posiblemente integrado por ejemplares del cruce entre la inglesa raza Shropshire Down con la autâ”œâ”‚ctona Rasa. Luego serâ”œآ،an regresadas al cercano aprisco de la Granja. A la izquierda, el puente de paso peatonal que, sobre las vâ”œآ،as del ferrocarril de Zaragoza a Barcelona, conducâ”œآ،a a la calle de la Granja Modelo. Al fondo, parcelas en el entorno del camino del Puente del Virrey y la calle del Once de Febrero, de la Nobleza, de la Alegrâ”œآ،a, de Don Ignacio de Buera, y de Don Joaquâ”œآ،n de Herrera. Fuente visual: exposiciâ”œâ”‚n أ”أ‡آ£La investigaciâ”œâ”‚n agroalimentaria en Aragâ”œâ”‚n. Sus inicios con Rodrâ”œآ،guez Ayusoأ”أ‡أک, Centro de Investigaciâ”œâ”‚n y Tecnologâ”œآ،a Agroalimentaria de Aragâ”œâ”‚n (CITA).', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63518400, -0.87141900, '0101000020E6100000E59D4319AAE2EBBFA37895B54DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33925662033.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33925662033.webp', 'https://www.flickr.com/photos/zaragozaantigua/33925662033/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23369, 'Esclusas de Valdegurriana 1833', '"Esclusas de Valdegurrian", litografâ”œآ،a de Faramundo Blanchard. Vista de las esclusas de Valdegurriana y la almenara de San Bernardo del Canal Imperial de Aragâ”œâ”‚n. Se trata de cuatro esclusas para facilitar la navegaciâ”œâ”‚n. Fuente visual: "Memoria histâ”œâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”œأ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', NULL, 41.61116500, -0.85628000, '0101000020E610000011018750A566EBBFDCBA9BA73ACE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19468297386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19468297386.webp', 'https://www.flickr.com/photos/zaragozaantigua/19468297386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24583, 'La Granja 1930', 'Imagen de la "estatua elevada en terrenos de la Granja por agricultores, ganaderos e industriales en recuerdo del insigne Director que fuâ”œآ® de este Centro Don Manuel Rodrâ”œآ،guez Ayuso". Fue inaugurada en 1915, dos aâ”œâ–’os despuâ”œآ®s del fallecimiento de Ayuso, y permaneciâ”œâ”‚ en esta ubicaciâ”œâ”‚n hasta que, tras unos aâ”œâ–’os desaparecida, fue recolocada (algo demediada) en las actuales instalaciones del Centro de Investigaciâ”œâ”‚n y Tecnologâ”œآ،a Agroalimentaria de Aragâ”œâ”‚n (CITA). Tras la isleta de la estatua, el edificio de la Direcciâ”œâ”‚n de la Granja Agrâ”œآ،cola, y uno de los pabellones principales. Fuente visual: "Granja Agrâ”œآ،cola de Zaragoza. Su cincuentenario. Homenaje y gratitud."', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34614442795.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34614442795.webp', 'https://www.flickr.com/photos/zaragozaantigua/34614442795/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24584, 'La Granja 1930', 'Imagen capturada en la Granja Agrâ”œآ،cola de Zaragoza, en la recoleta zona de ensayo de cultivos de hongos comestibles blancos, corrientemente designados con el nombre de "champignon", al objeto de evaluar su posible generalizaciâ”œâ”‚n tanto para la conserverâ”œآ،a como el consumo en fresco, a precio asequible. El â”œآ®xito en la experimentaciâ”œâ”‚n se tradujo en la extensiâ”œâ”‚n de este cultivo como complementario a otros cultivos principales, y sobre todo orientado al sector conservero. Fuente visual: www.mapama.gob.es/', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35075122142.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35075122142.webp', 'https://www.flickr.com/photos/zaragozaantigua/35075122142/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24585, 'Granja Agrâ”œآ،cola 1928', 'Imagen capturada con motivo de la exposiciâ”œâ”‚n de trabajos desarrollados por el Servicio Agronâ”œâ”‚mico de la Confederaciâ”œâ”‚n Sindical Hidrogrâ”œأ­fica del Ebro celebrada en la Granja Agrâ”œآ،cola de Zaragoza. En el posado figuran la direcciâ”œâ”‚n (destacando el fundador y primer Director Tâ”œآ®cnico de la instituciâ”œâ”‚n, Manuel Lorenzo Pardo Fuentes, de pie, en el centro de la imagen), Sâ”œآ،ndicos y los Vocales del Comitâ”œآ® de Aplicaciones de la Confederaciâ”œâ”‚n Sindical Hidrogrâ”œأ­fica del Ebro, ademâ”œأ­s del ingeniero-director de la Granja Agrâ”œآ،cola, Josâ”œآ® Cruz Lapazarâ”œأ­n Beristaâ”œآ،n (a la derecha, de pie, en primer tâ”œآ®rmino). De fondo escâ”œآ®nico, fachada del cuadrangular edificio de Oficinas y Direcciâ”œâ”‚n de la Granja Agrâ”œآ،cola, en el que ademâ”œأ­s se encontraban el laboratorio, biblioteca y Observatorio, domiciliado en el nâ”¬â•‘ 158 del barrio de Montemolâ”œآ،n. A espaldas del fotâ”œâ”‚grafo, fuera de plano, el Monumento inaugurado en 1913 a D. Manuel Rodrâ”œآ،guez Ayuso, "Director que fue de esta Granja Agrâ”œآ،cola, verdadero apâ”œâ”‚stol de la enseâ”œâ–’anza agraria". Fuente visual: foto Martâ”œآ،nez, en Revista Confederaciâ”œâ”‚n Sindical Hidrogrâ”œأ­fica del Ebro.', 1928, 1928, 1928, 'Anos 20', 'SAN JOSâ”œأ«', 41.63605300, -0.87058000, '0101000020E61000005DA79196CADBEBBFE7C2482F6AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45290946791.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45290946791.webp', 'https://www.flickr.com/photos/zaragozaantigua/45290946791/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25720, 'La Granja 1977', 'Fotografâ”œآ،a de la AVV. del Barrio de San Josâ”œآ®. 1977. Una de las "esquinas calientes" de la abandonada "Granja Agrâ”œآ،cola Experimental", "La Granja", como era denominada por los vecinos del barrio de S. Josâ”œآ®. Clausurada de sus originales funciones en 1943, sus solanas y resguardos a la cierzera pronto fueron detectados por los mayores que se venâ”œآ،an del pueblo con sus hijos durante el â”œآ®xodo rural de la segunda mitad de siglo. Hasta su derribo a finales de los aâ”œâ–’os 70, para construir un colegio pâ”œâ•‘blico, un parque y un centro deportivo municipal, fue un autâ”œآ®ntico centro social "al aire", cuando eso de los "centros de mayores" eran cosa inexistente. En la imagen, animada tertulia granjina con un telâ”œâ”‚n de fondo espectacular: las instalaciones abandonadas de la fâ”œأ­brica de cemento Portland, y el edificio residencial de la antigua Estaciâ”œâ”‚n de Miraflores.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15445665399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15445665399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15445665399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25730, 'Grupo &quot;Agustâ”œآ،n Gericâ”œâ”‚&quot; 1947', 'Imagen desde la Granja Agrâ”œآ،cola del Grupo "Agustâ”œآ،n Gericâ”œâ”‚", compuesto por 95 viviendas baratas impulsadas por el arcipreste Agustâ”œآ،n Gericâ”œâ”‚, y diseâ”œâ–’adas por Alejandro Allanegui y Josâ”œآ® de Yarza en una caracterâ”œآ،stica manzana triangular adaptada a la parcelaciâ”œâ”‚n de la zona. Ante ellas, el camino rural de moreras y acequia luego denominado Josâ”œآ® Galiay. A la derecha, los campos de cultivo de herbâ”œأ­ceas a los que se trasladarâ”œأ­ la Salle Montemolâ”œآ،n unas dâ”œآ®cadas despuâ”œآ®s. Fuente visual: AHPZ, Archivo Coyne', 1947, 1947, 1947, 'Anos 40', 'SAN JOSâ”œأ«', 41.63655800, -0.87127800, '0101000020E61000005E2D776682E1EBBFEB0088BB7AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20162543899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20162543899.webp', 'https://www.flickr.com/photos/zaragozaantigua/20162543899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25745, 'Cesâ”œأ­reo Alierta 1977', 'Imagen de la Avenida de Cesâ”œأ­reo Alierta como sorprendente espacio peatonal. Al fondo, la calle Cartagena y la parroquia de San Agustâ”œآ،n, el viejo edificio del "Despartidero" antes de su reforma (edificio entre la avenida de San Josâ”œآ® y el Camino del Puente del Virrey), y los restos de las antiguas parcelas de este sector de Miraflores. Fuente visual: AVV. San Josâ”œآ®', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.64036700, -0.87388500, '0101000020E6100000F4E0EEACDDF6EBBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20379517845.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20379517845.webp', 'https://www.flickr.com/photos/zaragozaantigua/20379517845/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25752, 'La Granja 1945', 'El Râ”œآ®gimen Franquista aliado del Eje Roma-Berlâ”œآ،n-Tokio seguâ”œآ،a siendo deficitario de productos como el algodâ”œâ”‚n. En 1940 estableciâ”œâ”‚, mediante la Ley de Racionalizaciâ”œâ”‚n y Fomento del Cultivo de Plantas Textiles, el "Instituto de Fomento del Cultivo del Algodonero", como encargado de encontrar soluciones en esta materia. Asâ”œآ،, estableciâ”œâ”‚ cuatro "zonas algodoneras", que fueron ampliadas aâ”œâ–’os despuâ”œآ®s hasta llegar al nâ”œâ•‘mero de 12. En 1941, la Granja Agrâ”œآ،cola de Zaragoza iniciâ”œâ”‚ los ensayos productivos del algodâ”œâ”‚n en tierras de regadâ”œآ،o, de forma exitosa. Asâ”œآ،, a finales de 1945 la provincia de Zaragoza fue incluida, junto con Huesca y Teruel, como nueva zona de producciâ”œâ”‚n nâ”¬â•‘ 8. Ese aâ”œâ–’o moldeâ”œâ”‚ sus primeras "balas" de algodâ”œâ”‚n "de tipo americano y fibra corta", de unos cuarenta kilos de peso cada una. A comienzos de 1946, la entidad "Algodonera del Ebro, S.A.", del importantâ”œآ،simo Grupo Sans, recibiâ”œâ”‚ la adjudicaciâ”œâ”‚n, por dos aâ”œâ–’os, de la "Zona octava algodonera". Los satisfactorios resultados alcanzados permitirâ”œأ­n a esta entidad recibir la concesiâ”œâ”‚n durante otras diez campaâ”œâ–’as, ampliando la zona a algunas comarcas de Navarra y Logroâ”œâ–’o. Casi veinte aâ”œâ–’os despuâ”œآ®s, en 1967 tedndrâ”œأ­ lugar la â”œâ•‘ltima campaâ”œâ–’a algodonera en la provincia de Zaragoza. La imagen recoge esa primera producciâ”œâ”‚n experimental, que auguraba un futuro exitoso y prometedor. Pero mientras el algodâ”œâ”‚n se convertâ”œآ،a en el privado "mejor negocio de la posguerra", la pâ”œâ•‘blica Granja Agrâ”œآ،cola de Zaragoza era clausurada y abandonada. Fuente visual: Revista "Aragâ”œâ”‚n", nâ”¬â•‘ 211.', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”œأ«', 41.63564100, -0.87072800, '0101000020E610000082C476F700DDEBBF957F2DAF5CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20583781071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20583781071.webp', 'https://www.flickr.com/photos/zaragozaantigua/20583781071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25761, 'P.â”¬â•‘ Marina Moreno 1976', 'Captura desde las alturas del edificio que ejercâ”œآ،a de "despartidero" entre la Avenida de San Josâ”œآ® y el arranque del Camino del Puente del Virrey, con imagen del estado de las obras de urbanizaciâ”œâ”‚n motivadas por la apertura al trâ”œأ­fico rodado de la prolongaciâ”œâ”‚n del paseo de Marina Moreno, en el tramo entre el Camino de las Torres (al fondo, a la izquierda) y la Avenida de San Josâ”œآ®. A la derecha, la gran manzana entre las calles de Castelar y Cartagena, en la que destaca el complejo de la antigua parroquia de San Agustâ”œآ،n. En su proyecto original, de finales de los aâ”œâ–’os sesenta, la prolongaciâ”œâ”‚n de Marina Moreno deberâ”œآ،a llegar hasta la carretera de Castellâ”œâ”‚n, por eso fue ideado como si de una multi-autopista se tratara, pasmo de la Zaragoza que irrumpâ”œآ،a con fuerza en la ultramodernidad formal. Por estos pagos, hasta no ha demasiado tiempo, perduraban campos de cultivo y huertas de los tiempos en que formaban parte del tâ”œآ®rmino de "Miralflores". Esta demediada prolongaciâ”œâ”‚n dio el pistoletazo de salida en esta zona a nuevos e interesantes polâ”œآ،gonos edilicios, y se quedâ”œâ”‚ estancada en este punto unos veinte aâ”œâ–’os, hasta que fue finalizada. Composiciâ”œâ”‚n inâ”œآ®dita, democrâ”œأ­tica, cientâ”œآ،fica y popular, generada en los laboratorios del', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”œأ«', 41.64028800, -0.87365800, '0101000020E6100000CA703C9F01F5EBBFB8020AF5F4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30147917751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30147917751.webp', 'https://www.flickr.com/photos/zaragozaantigua/30147917751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25764, 'Av. San Josâ”œآ® 1990', 'Imagen a la salida de la parroquia de San Agustâ”œآ،n, esquinera entre la avenida de San Josâ”œآ®, y el arranque de la calle de Cartagena, capturada durante los aâ”œâ–’os de complicada negociaciâ”œâ”‚n administrativa de expropiaciones aparejadas a la prolongaciâ”œâ”‚n de la avenida de Cesâ”œأ­reo Alierta. Dos aâ”œâ–’os despuâ”œآ®s comenzarâ”œأ­n los derribos, como el de la parroquia, que se trasladarâ”œآ،a a los bajos de un nuevo edificio del tramo prolongado, hacia la derecha. Fuente visual: www.zaragozarebelde.org/', 1990, 1990, 1990, 'Anos 90', 'SAN JOSâ”œأ«', 41.63991000, -0.87359500, '0101000020E6100000315F5E807DF4EBBF12312592E8D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32168008606.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32168008606.webp', 'https://www.flickr.com/photos/zaragozaantigua/32168008606/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25785, 'C.â”¬â•‘ del Puente del Virrey 1991', 'Imagen capturada en el gran solar conformado por el antiguo erial delimitado entre el camino del Puente del Virrey y las calles de Raquel Meller (a la izquierda y fuera de plano) y de Pablo Remacha (a la derecha y fuera de plano). Utilizado habitualmente como aparcamiento en superficie para vehâ”œآ،culos de todo tipo, y ocasionalmente para emplazar atracciones de feria, su situaciâ”œâ”‚n de abandono incluâ”œآ،a tambiâ”œآ®n episodios de chabolismo. Al fondo, la calle de â”œأ¼ngel Ganivet que conecta con la avenida de San Josâ”œآ®. Sobre este erial, y gracias a la reivindicaciâ”œâ”‚n vecinal, aâ”œâ–’os despuâ”œآ®s se trazarâ”œآ،a la actual plaza Mayor de San Josâ”œآ®.', 1991, 1991, 1991, 'Anos 90', 'SAN JOSâ”œأ«', 41.63803300, -0.87399200, '0101000020E610000075E61E12BEF7EBBF6762BA10ABD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50450918082.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50450918082.webp', 'https://www.flickr.com/photos/zaragozaantigua/50450918082/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25787, 'Miraflores c.1987', 'Los componentes del Vocoder, pionero grupo local de "tecno pop", posan en esta simpâ”œأ­tica imagen encaramados a una seâ”œâ–’alâ”œآ®tica del ferrocarril que comunica con Barcelona. Al fondo y a la izquierda, vista parcial de las viviendas ferroviarias junto a la estaciâ”œâ”‚n de Miraflores, que queda detrâ”œأ­s. En torno al gran y enorme Antonio Tenas, la vocalista Pilar Pellicer, Antonio Laval e Ildefonso Olarte.', 1987, 1987, 1987, 'Anos 80', 'SAN JOSâ”œأ«', 41.63391200, -0.86996900, '0101000020E61000001615713AC9D6EBBF5F45460724D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51768710027.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51768710027.webp', 'https://www.flickr.com/photos/zaragozaantigua/51768710027/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25789, 'Parroquia de San Agustâ”œآ،n 1967', 'Inâ”œآ®dita imagen capturada en el recoleto interior de la moderna parroquia de San Agustâ”œآ،n, establecida como tal desde el 8 de diciembre de 1966 de resultas de la divisiâ”œâ”‚n de la parroquia de San Vicente Mâ”œأ­rtir por el arzobispo Pedro Cantero Cuadrado para atender mejor a las 6.000 almas del barrio de San Josâ”œآ® aquâ”œآ، aparroquiadas. El pequeâ”œâ–’o tamaâ”œâ–’o del edificio tendrâ”œآ،a que ver posiblemente con que se trataba de la capilla de las "Obras Escolares, Catequâ”œآ،sticas y Religiosas de San Josâ”œآ®", con la que compartâ”œآ،a direcciâ”œâ”‚n postal en el nâ”¬â•‘ 10 de la calle de Cartagena. Ello explicarâ”œآ،a que la imagen que la preside sea un "San Josâ”œآ® con el niâ”œâ–’o" posiblemente de la Escuela de Olot, y no la preceptiva de San Agustâ”œآ،n. La ceremonia tiene lugar para oficiar el enlace de Carmen Lâ”œأ­zaro Sierra (hija de los guardeses de la Torre de Sarto) y Jesâ”œâ•‘s Hernâ”œأ­ndez Urbano.', 1967, 1967, 1967, 'Anos 60', 'SAN JOSâ”œأ«', 41.63927600, -0.87217900, '0101000020E6100000684128EFE3E8EBBF118FC4CBD3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52536045841.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52536045841.webp', 'https://www.flickr.com/photos/zaragozaantigua/52536045841/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22087, 'Facultad de Veterinaria 1951', 'La Facultad de Veterinaria de la Universidad de Zaragoza fue inaugurada en 1951. En la imagen se recoge el estado prâ”œâ”‚ximo al final de las obras de su edificio principal, comenzadas en abril de 1945, segâ”œâ•‘n proyecto de Santiago Lagunas, Manuel Martâ”œآ،nez de Ubago y Casimiro Lanaja de 1943. Estâ”œأ­ situada en la calle de Miguel Servet 177, donde â”œآ®sta terminaba y daba paso a la carretera de Castellâ”œâ”‚n. Sustituâ”œآ،a a la anterior sede, en la calle del General Sanjurjo, Fuente: Crâ”œâ”‚nica de 150 aâ”œâ–’os de estudios veterinarios en Aragâ”œâ”‚n. IFC, 2000.', 1951, 1951, 1951, 'Anos 50', 'SAN JOSâ”œأ«', 41.63465600, -0.86111800, '0101000020E6100000D6E6FF55478EEBBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18683881173.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18683881173.webp', 'https://www.flickr.com/photos/zaragozaantigua/18683881173/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22090, 'Joaquâ”œآ،n Ruiz-Gimâ”œآ®nez 1951', 'El Ministro de Educaciâ”œâ”‚n Nacional, Joaquâ”œآ،n Ruiz-Gimâ”œآ®nez, toma la palabra en el acto oficial de inauguraciâ”œâ”‚n de la nueva Facultad de Veterinaria de Zaragoza, el 20 de octubre de 1951. Este polâ”œآ،tico catâ”œâ”‚lico continuâ”œâ”‚ ejerciendo tras la muerte de Franco, llegando a ser el primer Defensor del Pueblo, entre 1982 y 1987. Fuente: Crâ”œâ”‚nica de 150 aâ”œâ–’os de estudios veterinarios en Aragâ”œâ”‚n. IFC, 2000.', 1951, 1951, 1951, 'Anos 50', 'SAN JOSâ”œأ«', 41.63465600, -0.86111800, '0101000020E6100000D6E6FF55478EEBBFE71A66683CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19117940378.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19117940378.webp', 'https://www.flickr.com/photos/zaragozaantigua/19117940378/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22454, 'Ctra. de Castellâ”œâ”‚n 1967', 'Imagen del silo denominado Zaragoza-Sur, o Zaragoza-Castellâ”œâ”‚n, del Servicio Nacional del Trigo, inaugurado en 1963 junto a la carretera de Castellâ”œâ”‚n, en una frontera ubicaciâ”œâ”‚n entre los parajes de La Cartuja Baja, el Rabalete, y Cabaldâ”œâ”‚s. Se trataba de un silo de tipo "D", de almacenamiento vertical con capacidad para 2300 toneladas mâ”œآ®tricas de cereales. La imagen se ha tomado desde la entrada de la que fuera casa de Gil Gonzâ”œأ­lez Marcilla. Aâ”œâ–’os despuâ”œآ®s, en tiempos del Servicio Nacional de Cereales, esta traza original se verâ”œآ،a modificada cuando se le anexara de forma descentrada un edificio administrativo en la fachada principal a la carretera. Fue derribado en 2019. Fuente visual: Cuadernos de Aragâ”œâ”‚n, 2, IFC', 1967, 1967, 1967, 'Anos 60', 'SAN JOSâ”œأ«', 41.63264700, -0.86024700, '0101000020E6100000766D6FB72487EBBFCD74AF93FAD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31616177237.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31616177237.webp', 'https://www.flickr.com/photos/zaragozaantigua/31616177237/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22530, 'Miguel Servet 1972', 'La lâ”œآ،nea 1 del Tranvâ”œآ،a ("Bajo Aragâ”œâ”‚n") llevaba rodando desde 1885, si bien entonces la tracciâ”œâ”‚n era "de sangre", y llegaba hasta la Estaciâ”œâ”‚n de Cappa. Electrificada en 1902, fue prolongada en 1953 hasta la nueva Facultad de Veterinaria. Fusionada en 1967 con la Lâ”œآ،nea 15 hasta Casablanca, en 1969 recuperâ”œâ”‚ su trayecto original: Pza. S. Miguel-Bajo Aragâ”œâ”‚n. En las fiestas matronales de 1975, fue suprimida. En la imagen, el tranvâ”œآ،a nâ”¬â•‘ 203 de la serie 200 a la altura de la Facultad de Veterinaria, en el bajo Miguel Servet. Fuente visual: www.flickr.com/photos/jhm0284/5812533003/in/photostream/', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”œأ«', 41.63497800, -0.86207200, '0101000020E61000009483D9041896EBBFF9D687F546D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14708661627.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14708661627.webp', 'https://www.flickr.com/photos/zaragozaantigua/14708661627/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22623, 'Cementera Miraflores 1975', 'Imagen de las instalaciones de la fâ”œأ­brica de Cementos de Miraflores capturada desde las inmediaciones de la Granja Agrâ”œآ،cola, entre riegos y caminos de acceso, campos de herbâ”œأ­ceas, y de maâ”œآ،z. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63145000, -0.86343500, '0101000020E6100000A818E76F42A1EBBF9487855AD3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19798875584.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19798875584.webp', 'https://www.flickr.com/photos/zaragozaantigua/19798875584/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22641, 'Cementera Miraflores 1979', 'Imagen de las instalaciones de la fâ”œأ­brica de Cementos de Miraflores capturada desde la metâ”œأ­lica pasarela peatonal que salvaba las vâ”œآ،as del ferrocarril de Madrid a Barcelona. Abandonada desde hacâ”œآ،a aâ”œâ–’os, pronto serâ”œأ­ derribada.', 1979, 1979, 1979, 'Anos 70', 'SAN JOSâ”œأ«', 41.63145000, -0.86343500, '0101000020E6100000A818E76F42A1EBBF9487855AD3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20413473722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20413473722.webp', 'https://www.flickr.com/photos/zaragozaantigua/20413473722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22774, 'Miguel Servet 1972', 'Despejada imagen centrada en la unidad 222 de la serie de los "gaditanos" en servicio en la tranviaria lâ”œآ،nea 1 "Bajo Aragâ”œâ”‚n", localizada en la terminal inmediata a la nueva Facultad de Veterinaria y preparada para encaminarse a la plaza de San Miguel. Esta Facultad fue inaugurada en 1951 en el tramo bajo de la calle de Miguel Servet. A la derecha de la fachada principal de Veterinaria, el solar donde aâ”œâ–’os mâ”œأ­s tarde (1977) serâ”œآ،a inaugurado el reivindicado pabellâ”œâ”‚n de Zootecnia y Tecnologâ”œآ،a de los Alimentos. Tras la clausura de la lâ”œآ،nea en 1975, este tranvâ”œآ،a fue desguazado. Fuente visual: colecciâ”œâ”‚n Josep Miquel Solâ”œآ®.', 1972, 1972, 1972, 'Anos 70', 'SAN JOSâ”œأ«', 41.63466800, -0.86165300, '0101000020E61000005C02F04FA992EBBFABE80FCD3CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34161763193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34161763193.webp', 'https://www.flickr.com/photos/zaragozaantigua/34161763193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24478, 'Fielato carretera Castellâ”œâ”‚n 1962', 'En 1962 existâ”œآ،an en Zaragoza siete oficinas auxiliares de arbitrios o fielatos, que cobraban impuestos sobre algunas mercancâ”œآ،as que entraban a la ciudad, a cargo de la Policâ”œآ،a Sanitaria de Abastos. La de la imagen, en la carretera de Castellâ”œâ”‚n, junto a la antigua vivienda de Gil Gonzâ”œأ­lez Marcilla, era denominada La Cartuja. Las otras cinco fueron La Venta, en la carretera de Huesca; la de la carretera de Barcelona, junto al puente de Santa Isabel; Casablanca, en la carretera de Valencia; Carabinas, en la de Madrid; y Caminreal, al final del paseo de Pamplona, junto a la carretera de Logroâ”œâ–’o. En 1961 se habâ”œآ،a inaugurado tambiâ”œآ®n una caseta en la calle Asalto, junto al Corral de la Leâ”œâ–’a.', 1962, 1962, 1962, 'Anos 60', 'SAN JOSâ”œأ«', 41.63295700, -0.85981900, '0101000020E61000007157AF22A383EBBF1B6327BC04D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21636790192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21636790192.webp', 'https://www.flickr.com/photos/zaragozaantigua/21636790192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24517, 'Miraflores 1929', 'Imagen de la nueva fâ”œأ­brica de cementos Portland de Zaragoza "Alfonso XIII", ubicada en Miraflores, entre las lâ”œآ،neas del ferrocarril MZA y de Utrillas, capturada antes de su inauguraciâ”œâ”‚n y puesta en funcionamiento. La imagen se habrâ”œآ،a capturado desde el "camino a la Fâ”œأ­brica de Cementos" que la conectaba con la carretera de Castellâ”œâ”‚n. En primer tâ”œآ®rmino, posiblemente una casilla de vialidad y obras de la lâ”œآ،nea de Utrillas, y a la derecha, el notable edificio de la Direcciâ”œâ”‚n de la fâ”œأ­brica. Al fondo, las modernas instalaciones de la fâ”œأ­brica para el tratamiento de â”œأ­ridos (arcilla, caliza y margas) y su conversiâ”œâ”‚n en cemento. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'SAN JOSâ”œأ«', 41.63314400, -0.86333700, '0101000020E6100000F4A78DEA74A0EBBF4ED4D2DC0AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35337417925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35337417925.webp', 'https://www.flickr.com/photos/zaragozaantigua/35337417925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24861, 'Calle de Miguel Servet c.1987', 'Inâ”œآ®dita imagen capturada durante la construcciâ”œâ”‚n de las nuevas cocheras para la empresa Transportes Urbanos de Zaragoza S.A., con diseâ”œâ–’o del arquitecto Josâ”œآ® Marâ”œآ،a Valero Suâ”œأ­rez, en su nueva ubicaciâ”œâ”‚n de la calle de Miguel Servet nâ”¬â•‘ 199. En primer tâ”œآ®rmino, los nuevos accesos desde esta calle-carretera, que confrontan con el principio del camino de Enmedio, y con el antiguo silo "Zaragoza-Castellâ”œâ”‚n", del Servicio Nacional de Cereales.', 1987, 1987, 1987, 'Anos 80', 'SAN JOSâ”œأ«', 41.63253200, -0.85782400, '0101000020E6100000392A37514B73EBBF34D6FECEF6D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32652380807.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32652380807.webp', 'https://www.flickr.com/photos/zaragozaantigua/32652380807/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
